    38→/// 3D coordinate structure
    39→#[derive(Debug, Clone, Copy, PartialEq)]
    40→pub struct Coord3D {
    41→    pub x: f32,
    42→    pub y: f32,
    43→    pub z: f32,
    44→}
    45→
    46→impl Coord3D {
    47→    pub fn new(x: f32, y: f32, z: f32) -> Self {
    48→        Self { x, y, z }
    49→    }
    50→
    51→    pub fn zero() -> Self {
    52→        Self::new(0.0, 0.0, 0.0)
    53→    }
    54→
    55→    pub fn dot(&self, other: &Coord3D) -> f32 {
    56→        self.x * other.x + self.y * other.y + self.z * other.z
    57→    }
    58→
    59→    pub fn distance_to(&self, other: &Coord3D) -> f32 {
    60→        let dx = self.x - other.x;
    61→        let dy = self.y - other.y;
    62→        let dz = self.z - other.z;
    63→        (dx * dx + dy * dy + dz * dz).sqrt()
    64→    }
    65→}
